    datosExtraidos.dia_cita = datos.dia_cita || "";
    datosExtraidos.hora_cita = datos.hora_cita || "";
  } catch (e) {
    try {
      const textoJson = partes[1].trim();
      if (textoJson.match(/"dia_cita"\s*:\s*"([^"]*)"/)) datosExtraidos.dia_cita = textoJson.match(/"dia_cita"\s*:\s*"([^"]*)"/)[1];
